import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { AuthService } from '../../../servicos/auth.service';
import { LoadingController, ToastController } from '@ionic/angular';

@Component({
  selector: 'app-login',
  templateUrl: './login.page.html',
  styleUrls: ['./login.page.scss'],
})
export class LoginPage implements OnInit {
  formulario: FormGroup;
  modoRegistro = false;

  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private router: Router,
    private loadingCtrl: LoadingController,
    private toastCtrl: ToastController
  ) {
    this.formulario = this.fb.group({
      email: ['passageiro1@mototaxi.local', [Validators.required, Validators.email]],
      senha: ['123456', [Validators.required, Validators.minLength(6)]],
      nome: [''],
      papel: ['passageiro']
    });
  }

  ngOnInit() {}

  async entrarComoPassageiro() {
    await this.fazerLoginRapido('passageiro1@mototaxi.local', '123456', 'passageiro');
  }

  async entrarComoMotorista() {
    await this.fazerLoginRapido('moto1@mototaxi.local', '123456', 'motociclista');
  }

  async fazerLoginRapido(email: string, senha: string, papel: string) {
    const loading = await this.loadingCtrl.create({
      message: 'Entrando...'
    });
    await loading.present();

    try {
      await this.authService.entrar(email, senha).toPromise();
      
      if (papel === 'passageiro') {
        this.router.navigate(['/passageiro/mapa']);
      } else if (papel === 'motociclista') {
        this.router.navigate(['/motociclista/chamadas']);
      }
    } catch (erro: any) {
      const toast = await this.toastCtrl.create({
        message: erro?.message || 'Erro ao fazer login',
        duration: 3000,
        color: 'danger'
      });
      await toast.present();
    } finally {
      await loading.dismiss();
    }
  }

  alternarModo() {
    this.modoRegistro = !this.modoRegistro;
    if (this.modoRegistro) {
      this.formulario.get('nome')?.setValidators([Validators.required]);
    } else {
      this.formulario.get('nome')?.clearValidators();
    }
    this.formulario.get('nome')?.updateValueAndValidity();
  }

  async enviar() {
    if (this.formulario.invalid) {
      const toast = await this.toastCtrl.create({
        message: 'Preencha todos os campos corretamente',
        duration: 3000,
        color: 'warning'
      });
      await toast.present();
      return;
    }

    const loading = await this.loadingCtrl.create({
      message: this.modoRegistro ? 'Criando conta...' : 'Entrando...'
    });
    await loading.present();

    const { email, senha, nome, papel } = this.formulario.value;

    try {
      if (this.modoRegistro) {
        await this.authService.registrar({ email, senha, nome, papel }).toPromise();
        const toast = await this.toastCtrl.create({
          message: 'Conta criada com sucesso! Faça login.',
          duration: 3000,
          color: 'success'
        });
        await toast.present();
        this.alternarModo();
      } else {
        await this.authService.entrar(email, senha).toPromise();
        const usuario = await this.authService.obterUsuario().toPromise();
        
        if (usuario?.papel === 'passageiro') {
          this.router.navigate(['/passageiro/mapa']);
        } else if (usuario?.papel === 'motociclista') {
          this.router.navigate(['/motociclista/chamadas']);
        } else {
          this.router.navigate(['/selecionar-perfil']);
        }
      }
    } catch (erro: any) {
      const toast = await this.toastCtrl.create({
        message: erro?.error?.detail || 'Erro ao processar solicitação',
        duration: 4000,
        color: 'danger'
      });
      await toast.present();
    } finally {
      await loading.dismiss();
    }
  }
}
<ion-header>
  <ion-toolbar color="primary">
    <ion-title>{{ modoRegistro ? 'Criar Conta' : 'Entrar' }}</ion-title>
  </ion-toolbar>
</ion-header>

<ion-content class="ion-padding">
  <div class="logo-container">
    <h1>🏍️ Moto Táxi</h1>
    <p>Mobilidade urbana rápida e segura</p>
    <p class="subtitle">App do Passageiro</p>
  </div>

  <!-- Login Rápido - Modo Passageiro -->
  <ion-card class="login-rapido">
    <ion-card-header>
      <ion-card-title>Entrar como Passageiro</ion-card-title>
    </ion-card-header>
    <ion-card-content>
      <ion-button expand="block" color="primary" size="large" (click)="entrarComoPassageiro()">
        <ion-icon name="person" slot="start"></ion-icon>
        Entrar Agora
      </ion-button>
      <p class="hint">Clique para começar a usar o app</p>
    </ion-card-content>
  </ion-card>

  <div class="divider">
    <span>ou use credenciais personalizadas</span>
  </div>

  <form [formGroup]="formulario" (ngSubmit)="enviar()">
    <ion-item>
      <ion-label position="floating">E-mail</ion-label>
      <ion-input formControlName="email" type="email"></ion-input>
    </ion-item>

    <ion-item>
      <ion-label position="floating">Senha</ion-label>
      <ion-input formControlName="senha" type="password"></ion-input>
    </ion-item>

    <ion-button expand="block" type="submit" class="ion-margin-top">
      Entrar
    </ion-button>
  </form>
</ion-content>
